import React, { useState } from "react";

const Addition = () => {
  const [sum, setSum] = useState(0);
  const [first, setFirst] = useState(0);
  const [second, setSecond] = useState(0);
  const add = () => {
      setFirst((first) => parseInt(document.getElementById("num1").value)
       );

        setSecond((second) => parseInt(document.getElementById("num2").value)
       );
      setSum((sum) => first + second);

}
  return (
    <div className="Addition">

      <body>
      <p>First Number: <input id="num1"/> </p>
      <p>Second Number: <input id="num2" /> </p>
     <button type="button" class="btn btn-primary" onClick={add}>Add Them</button>
      <p>Sum = {sum} </p>
   </body>

    </div>
  );
};

export default Addition;
